    private void createDefDB(String apname, User access,long maxHistoryAge,boolean noNotification,boolean noUploads) {
        Path dbDefPath = Paths.get("cust","tmp","s3backup_" + apname + ".ragicz");
        Log log=new Log("log/movedb.log").setIfDisplayTime(true);
        log.info("Move DB of "+apname+" started.");

        try (BufferedOutputStream bos = new BufferedOutputStream(new FileOutputStream(dbDefPath.toFile()))) {
            BackupDB.createCompressedBackup(apname, bos, false, noUploads, access, maxHistoryAge, noNotification);
        } catch (IOException e) {
            e.printStackTrace();
        }
        log.info("DB extraction of "+apname+" complete, start uploading.");

        String s3name = RagicConfig.getInstance().getProperty("SERVER_NAME") + "/" + apname + "/dbDefFile";
//        String s3name = "39b22b5e.ngrok.io" + "/" + apname + "/dbDefFile";

        S3Helper.upload(Const.S3_BUCKET_BACKUP, s3name, dbDefPath.toFile());
        log.info("DB upload of "+apname+" complete. No more job at this side.");

        //delete the file
        try {
            Files.delete(dbDefPath);
            log.info("CSV file for "+apname+" deleted.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

